var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그럼 현 상황 보고드리겠습니다.","JPN":"では、現状況について報告します。","ENG":"Then I'll give a report on the current situation.","TWN":"那我開始報告現況。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"CSE Lv.6으로 인한 국지적 현실 붕괴로 인해 제6종 침식체, 식별명 세피라의 수호자가 프론트 베이 대균열에 강림했습니다.","JPN":"CSE Lv.6による局地的な現実崩壊により第6種侵食体、識別名セフィラの守護者がフロントベイ大亀裂に降臨しました。","ENG":"Due to the Local Reality Collapse caused by CSE Level 6, a Category 6 C.O. named \\"Guardian of Sephira\\" manifested at the Front Bay's Grand Dimension Crevice.","TWN":"因CSE Lv.6引發局部現實崩壞的6類侵蝕體，識別名塞菲拉守護者已降臨前灣大峽谷。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"프론트 베이 관리국은 정해진 절차에 따라 선로전환기를 가동하기 위한 준비에 들어갔었으나…….","JPN":"フロントベイ管理局は取り決められた手続きに従い、線路転換器を稼働するための準備に移りましたが……","ENG":"The Front Bay Administration had begun preparations to activate the Track Switcher as per protocol, but...","TWN":"前灣管理局本來依照既定程序準備啟動線路轉換器……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어 잭 에이버리의 결단으로 선로전환기 가동 절차는 중단.","JPN":"シニア - ジャック・エイバリーの決断で線路転換器の稼働手続きを中断。","ENG":"By the decision of Senior Jack Avery, Track Switcher activation was halted.","TWN":"但因Senior·傑克·艾維利的決定，已中斷線路轉換器啟動程序。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"모든 동력을 인빈서블Mk2의 차원 도약에 소모했습니다.","JPN":"全動力をインビンシブルMk2の次元跳躍に消費しました。","ENG":"All power was diverted into the Invincible Mk.2's dimension jump.","TWN":"所有動力皆投入無敵號Mk2的次元跳躍。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 곤란하게 되었군.","JPN":"ふむ、参ったな。","ENG":"Hmm. That puts us in a difficult position.","TWN":"唔，這就麻煩了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 된다면 프론트 베이의 대균열은 타기리온의 의도대로 흘러가겠어.","JPN":"そうなるとフロントベイの大亀裂はタギリオンの意図通りに事が進んでいくだろうね。","ENG":"If that's the case, the Front Bay's Grand Dimension Crevice will proceed according to Thagirion's plans.","TWN":"這麼一來，前灣的大峽谷就會照塔基里翁的意圖發展。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직할 도시의 상황은 어떤가?","JPN":"直轄都市の状況はどうだ？","ENG":"What's the status of the Administration Direct Control City?","TWN":"直轄城市的情況如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"프론트 베이의 격벽은 지난 검은 범람부터 견디기 어려울 것으로 예측되었습니다.","JPN":"フロントベイの隔壁は、前回の黒い氾濫の時点ですでに限界に近く、今回に至っては耐えきれないだろうと予測されました。","ENG":"The Front Bay bulwark had already been predicted to fail since the previous Black Flood.","TWN":"我們預測前灣的隔離牆在黑色洪災後就無法承受了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"따라서 시니어님의 지시로 격벽을 열어 피해를 최소화하고 사냥꾼들을 단합시켜 크라켄을 한차례 격퇴에 성공했습니다.","JPN":"そのため、シニア様の指示で隔壁を開いて被害を最小限に抑え、海賊とハンターたちと力を合わせてクラーケンを一度撃退しました。","ENG":"Thus, under Senior's orders, the bulwark was opened to minimize damage, and pirates and hunters were united to repel Kraken once.","TWN":"所以依照Senior的指示，開啟隔離牆減少損害並團結獵人，成功擊退一次克拉肯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"여기서부턴 제가 보고하도록 하겠습니다.","JPN":"ここからは私に報告させてください。","ENG":"I'll take over the report from here.","TWN":"這部分由我來報告。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"현재 프론트 베이의 격벽은 크라켄의 직접적인 타격으로 대파.","JPN":"現在フロントベイの隔壁はクラーケンの直接的な打撃により大破。","ENG":"The Front Bay bulwark has been destroyed by a direct strike from Kraken.","TWN":"目前前灣的隔離牆已被克拉肯直接摧毀，"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"더 이상 격벽으로써의 기능을 상실한 상태입니다.","JPN":"隔壁としての機能は失われた状態です。","ENG":"It can no longer function as a bulwark.","TWN":"隔離牆已經完全喪失作用了。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그리고 대균열로부터 뻗어 나온 것으로 추정되는 나무뿌리가 프론트 베이, 나아가 바다 곳곳을 잠식한 상황입니다.","JPN":"そして大亀裂から伸びてきたと推測される木の根がフロントベイをはじめ、海の各所を侵食しています。","ENG":"And what appear to be roots extending from the Grand Dimension Crevice have begun overtaking Front Bay and the surrounding sea.","TWN":"從大峽谷延伸的樹根疑似正在侵蝕前灣，甚至延伸到大海各處。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"……임무를 무사히 수행하지 못한 점에 대해 사죄드립니다.","JPN":"……任務を完遂できず申し訳ございません。","ENG":"...I apologize for failing to complete the mission.","TWN":"……無法完成任務，我深感抱歉。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 현장 지휘관인 제 판단에 따라 이 조치가 앞으로를 대비할 수 있는 가장 좋은 수라고 판단하였습니다.","JPN":"ですが現場の指揮官として、この措置が今後に備えるための最善の策だと判断しました。","ENG":"However, as the commanding officer on site, I judged this course to be the best possible choice for what comes next.","TWN":"但我身為現場指揮官，我判斷這是為未來做好準備的最佳選擇。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로를 대비한다는 자네의 말, 생각을 좀 들어보고 싶군.","JPN":"今後に備えるということについて、詳しく聞かせてくれるかね。","ENG":"You say it was to prepare for the future. Tell me what you mean by that.","TWN":"你說為了未來，我想聽聽你的想法。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"과거는 미래로 이어져야 합니다.","JPN":"過去は未来へ繋がるべきものです。","ENG":"The past must feed into the future.","TWN":"過去必須接續未來。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"사람들은 오늘이 아닌 내일을 생각할 수 있어야 합니다.","JPN":"人々は今日ではなく明日を思えるようにならねばなりません。","ENG":"People must be able to think about tomorrow, not just today.","TWN":"人們除了今天以外，必須要能思考明天。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그건 제가 20년 전 바다로 나온 그때부터, 모든 걸 바다에 묻고 시니어가 된 지금까지 변하지 않은 생각입니다.","JPN":"20年前に海に出た時から、すべてを海に沈めてシニアになった今に至るまで、変わらない私の見解です。","ENG":"That belief hasn't changed since the day I first set out to sea twenty years ago. Nor now, after burying everything in the ocean and becoming a Senior.","TWN":"這是我從20年前踏上海洋、將所有一切埋葬在大海、直到成為Senior都不曾改變的信念。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"선로전환기를 가동하고, 사도의 진격을 저지하는 대신 우리의 전력들을 잃는다면…….","JPN":"線路転換器を稼働し、使徒の進撃を阻止する代わりにこちらの戦力を失うならば……","ENG":"If we activate the Track Switcher and halt the Apostle's advance but lose our forces in the process...","TWN":"如果啟動線路轉換器，阻止使徒前進，但讓我們的戰力全毀……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그것은 미래를 잃는 것과 마찬가지일 겁니다.","JPN":"それは未来を失うことも同然です。","ENG":"Then we would be losing our future.","TWN":"那就等於失去未來。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"관리자님의 소중한 사원들을 세피라의 수호자가 나타날 수 있는 곳까지 파견 보냈다는 것은,","JPN":"最高管理者の大事な社員を、セフィラの守護者が出現し得る場所に派遣したのは……","ENG":"The fact that you dispatched your valuable personnel to regions where the Guardian of Sephira could appear...","TWN":"從把管理者珍貴的職員派到塞菲拉守護者可能降臨的地點來看，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"제가 모두를 살려 보낼 수 있을 거라는 믿음이 있기에 가능한 조치였겠지요.","JPN":"私なら全員を生還させられると信じた上での措置だったのでしょう。","ENG":"It must mean you believed I could bring them all back alive.","TWN":"代表您相信我能讓所有人活著回來。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 가장 높이 샀던 점은, 바로 그런 점이었네.","JPN":"君を高く評価した一番の理由は、そういうところだ。","ENG":"And that belief is what I valued most in you.","TWN":"我最看重的就是你這一點。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"꺾이지 않는 마음, 자신에 대한 확고한 신념.","JPN":"折れない心、己に対する確固たる信念。","ENG":"An unyielding heart. The unshakable conviction in yourself.","TWN":"堅定不移的心、堅信自己的信念。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 인간을 향한 끝없는 믿음.","JPN":"そして人間への果てなき信頼。","ENG":"And an endless faith in humanity.","TWN":"還有對人無盡的信任。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"20년 전과 지금의 자네는 하나도 변하지 않았어.","JPN":"君は20年前とまったく変わっていない。","ENG":"You haven't changed at all from twenty years ago.","TWN":"你和20年前一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보니 양이 마지막까지 놓지 않았던 자네를 향한 믿음은…….","JPN":"ボニー君が最後まで手放さなかった君への信頼は……","ENG":"Bonny's unwavering faith in you...","TWN":"寶妮直到最後都沒有放棄相信你……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결국 틀리지 않았다는 것을 증명했네.","JPN":"間違いではなかったと、証明してくれたね。","ENG":"Has finally been proven correct.","TWN":"事到如今也證明她是對的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 결국 세피라의 수호자가 현실에 강림하고 말았습니다.","JPN":"しかし、結局セフィラの守護者が現実に降臨してしまいました。","ENG":"But the Guardian of Sephira did descend into reality after all.","TWN":"但最終塞菲拉守護者還是降臨現實了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"또한 그 여파로 현실 세계의 차원 계면이 약해질 것이 우려스럽군요.","JPN":"その影響で現実世界の次元界面が弱まってしまうことが心配です。","ENG":"And I'm concerned that its arrival will further weaken the dimension surface of the Normalside.","TWN":"而這股餘波可能讓現實世界的次元界面變得更脆弱。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"언젠가는 벌어질 일이었어.","JPN":"いつかは起こることだったんだ。","ENG":"It was inevitable someday.","TWN":"這是終究會發生的事。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기로는 나무뿌리의 잠식을 막지 못하네.","JPN":"線路転換器は木の根の侵食を止められない。","ENG":"The Track Switcher cannot stop the roots' spread.","TWN":"線路轉換器無法抵擋樹根的侵蝕。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기로는 사도의 진격을 늦출 뿐, 결국 그들은 현실 세계에 도달하지.","JPN":"線路転換器は使徒の進撃を遅らせるだけで、彼らはいずれ現実世界にたどり着く。","ENG":"The Track Switcher only slows an Apostle's advance. They reach the Normalside regardless.","TWN":"它只能減緩使徒的推進，最終它們還是會抵達現實世界。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기로는 세피라의 수호자를 막아낼 방법이 전혀 없어.","JPN":"あの装置はセフィラの守護者を止める手段になりえないのだよ。","ENG":"And the Track Switcher has no method whatsoever to stop the Guardian of Sephira.","TWN":"而線路轉換器完全沒辦法阻止塞菲拉守護者。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어차피 터질 댐이라면, 차라리 이런 식으로 물꼬를 터주는 편이 더 나을 거야.","JPN":"いつか決壊するダムなら、いっそのことこうやって水門を開けてやったほうがまだマシだろう。","ENG":"If a dam is doomed to burst, it may be better to release the pressure like this instead.","TWN":"反正那座水壩早晚都會潰堤，那倒不如乾脆像這樣直接洩洪比較好。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런 일을 대비해서 내가 있는 게 아니겠나?","JPN":"それに、こういう事態に備えるために私がいるんだしね。","ENG":"And that's why I'm here, is it not?","TWN":"我就是為了準備這種事才會待在這裡不是嗎？"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 지역에도 차원 계면이 약해진 곳을 통해 세피라의 수호자가 강림할 수 있으니 이에 대한 이야기를 전달해 두겠네.","JPN":"他の地域にも次元界面が弱くなった場所を狙ってセフィラの守護者が降臨する可能性があるから、この件については伝えておこう。","ENG":"I'll inform the other regions. The Guardian of Sephira may descend through weakened dimension surfaces elsewhere as well.","TWN":"我會把消息傳到其他地區，提醒他們塞菲拉守護者有可能透過脆弱的次元介面降臨。"},"stage":{"bg":"OMEN_FRONTBAY_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"최고 관리자님께서도 이제 앞을 예측할 수 없다고 들었습니다.","JPN":"最高管理者も、もうこれからのことは予測できないと聞きました。","ENG":"I've heard even you can no longer predict what lies ahead.","TWN":"說最高管理者現在也無法再預測前方了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아무것도 보이지 않는 망망대해의 바다에서… 최고 관리자님은 어떻게 나아가실 생각입니까?","JPN":"何も見えない大海原で……最高管理者はどう進むつもりですか？","ENG":"In this vast ocean where nothing can be seen... how do you plan to move forward, Supreme Administrator?","TWN":"在這片伸手不見五指的大海……最高管理者打算怎麼走？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나도 여느 인간과 다를 바 없네.","JPN":"私とて普通の人間となんら変わりない。","ENG":"I'm no different from any other human.","TWN":"我也和普通人一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"폭풍우를 두려워하고, 어둠에 막막해하지.","JPN":"嵐を恐れ、闇の前で途方に暮れる。","ENG":"I fear storms, and I grow uneasy in the dark.","TWN":"會畏懼暴風雨，在黑暗裡會不知所措。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만… 보니 양이 말했던 것처럼 어두운 바다에는 항해사가 있다면 어떻게든 헤쳐 나갈 수 있네.","JPN":"だが……ボニー君が言ったように、暗い海でも航海士がいればなんとか前に進めるのさ。","ENG":"But... as Bonny once said, even a dark sea can be crossed if you have a navigator.","TWN":"但……就像寶妮說的，只要有航海士，也能想辦法突破漆黑的海。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고… 그 항해사들이 바로 자네들, 시니어들이지.","JPN":"そして……その航海士とは君たち、シニアだ。","ENG":"And those navigators... are you Seniors.","TWN":"而那些航海士……就是你們Senior。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들은 과거에 이어진 인연들을 그러모아 현재에 이르게 했네.","JPN":"君たちは過去の絆をまとめ上げ、現在につなげた。","ENG":"You gathered the bonds built in the past and carried them into the present.","TWN":"他們串起過去積累的因緣走到現在。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그것들은 이윽고 나에게 닿아…….","JPN":"そしてそれらはやがて私に届き……","ENG":"And those bonds finally reached me...","TWN":"而那些因緣最終來到我身邊……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비로소 내일을 꿈꾸게 했지.","JPN":"明日を夢見させてくれた。","ENG":"And allowed me to dream of tomorrow.","TWN":"才讓我能夢想明天。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 세계라는 배의 선장을 나에게 맡겨줘 감사함을 표하는 바이네.","JPN":"私にこの世界という船の船長をやらせてくれたこと、心から感謝しているよ。","ENG":"For entrusting me with the helm of this ship we call the world, you have my gratitude.","TWN":"謝謝你把這艘名為世界的船交給我掌舵。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번 항해는 반드시…….","JPN":"今回の航海は必ず……","ENG":"I'll make sure this voyage will...","TWN":"這次航行，我一定……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"내일에 닿을 수 있도록 하지.","JPN":"明日に繋げてみせる。","ENG":"Reach tomorrow.","TWN":"會把船駛向明天。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};